    if not url or not isinstance(url, str):
        return False, "Invalid URL: URL must be a non-empty string"

    # Parse the URL
    try:
        parsed = urllib.parse.urlparse(url)
    except Exception as e:
        return False, f"Invalid URL format: {str(e)}"

    # Check scheme - only allow http and https
    if parsed.scheme not in ('http', 'https'):
        return False, f"Invalid URL scheme: Only http and https are allowed, got '{parsed.scheme}'"

    # Check if hostname exists
    if not parsed.netloc:
        return False, "Invalid URL: No hostname provided"

    # Extract hostname (remove port if present)
    hostname = parsed.hostname
    if not hostname:
        return False, "Invalid URL: Could not extract hostname"

    # Block localhost variations
    localhost_patterns = [
        'localhost',
        'localhost.localdomain',
        '0.0.0.0',
    ]
    if hostname.lower() in localhost_patterns:
        return False, f"Access to localhost is not allowed"

    # Resolve hostname to IP and check if it's private
    try:
        # Get all IP addresses for the hostname
        addr_info = socket.getaddrinfo(hostname, None)
        for info in addr_info:
            ip_str = info[4][0]
            if is_private_ip(ip_str):
                return False, f"Access to private/internal IP addresses is not allowed: {ip_str}"
    except socket.gaierror:
        return False, f"Could not resolve hostname: {hostname}"
    except Exception as e:
        return False, f"Error validating hostname: {str(e)}"

